const dbStatus = supabaseLogged > 0 ? '💾 ' + supabaseLogged + ' items logged to Supabase' : '⚠️ Supabase log failed';
const fullMsg = whatsappMsg + '\n' + dbStatus;

const msgBody = JSON.stringify({ number: '14432576836@s.whatsapp.net', textMessage: { text: fullMsg } });
const opts = {
  hostname: 'host.docker.internal', port: 8081,
  path: '/message/sendText/Aidan', method: 'POST',
  headers: { 'Content-Type': 'application/json', 'apikey': 'Kevin2026', 'Content-Length': Buffer.byteLength(msgBody) }
};
await new Promise(function(r) {
  const req = http.request(opts, function(res) { res.on('data', function(){}); res.on('end', r); });
  req.on('error', r); req.write(msgBody); req.end();
