};
const cbReq = http.request(cbOpts, function(res) { res.on('data', function(){}); res.on('end', function(){}); });
cbReq.on('error', function(){});
cbReq.write(cbBody);
cbReq.end();

return [{ json: { success: true, agent: 'Iris', version: 'v3', summary: summary, supabaseLogged: supabaseLogged } }];
